import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.DpI_zlPE.js";var i=JSON.parse(`{"title":"手机","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/无线路由器/手机.md","filePath":"ccc/无线路由器/手机.md"}`),a={name:`ccc/无线路由器/手机.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="手机" tabindex="-1">手机 <a class="header-anchor" href="#手机" aria-label="Permalink to “手机”">​</a></h1><p>2022.5.4</p><p><a href="https://xiaomi.wxlnk.com" target="_blank" rel="noreferrer">小米澎湃优化</a>；</p><p>TSMC N3节点提升较小，还涨价，而台积电2nm，导入GAA，恐有巨大提升，有成为钉子户潜力。预计相关产品要等到2025年末才会上市。</p><p>芯片性能请参考工艺密度。</p><p>跑分只测爆发性能，厂商还会作弊，半导体性能是硬参数。</p><p>游戏看PPA，不玩游戏看能耗比。</p><p><img src="https://s2.loli.net/2022/05/04/GoN5LjTH2YdMxAr.png" alt="工艺密度.png"></p><ul><li>千元机红米，iqoo，realme都可以考虑。</li><li>2000以上价位除非玩手游，否则应关注颜值，手感等细节 ，需要去实体店体验。</li><li>刚发布前三个月不要买，小毛小病概率大，手机系统出厂都是半成品，打磨几个月才会稳定。</li></ul><p>我个人认为ov上限不行，即使取得一时的领先也没用。举两个例子管中窥豹：</p><p>1、一加品牌没有长期主义的决心，朝令夕改。</p><p>2、一样交保护费，华为小米徕卡标的产品，adobe camera raw都进行了适配，ps就能处理raw。ov牛逼吹得震天响raw不够，还得是super raw！竟然不是线性响应的。adobe camera raw的处理配置生成流程是公开的，另外还有开源的处理方案，厂家即使不交保护费也完全可以自己发布配置文件，这是没有主人翁精神的直接体现，管他功能有没有实用性。</p><h2 id="充电头" tabindex="-1">充电头 <a class="header-anchor" href="#充电头" aria-label="Permalink to “充电头”">​</a></h2><p>参考<a href="https://www.chongdiantou.com" target="_blank" rel="noreferrer">充电头网</a>的测试，京东京造和倍思，性价比相对比较高。</p><p>根据测试，只要协议支持，充电速度没区别。</p>`,15)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};